import React from 'react';
import { Trash2, Calendar, Tag, Package } from 'lucide-react';

const ListaOfertas = ({ ofertas, onDelete }) => {
  if (ofertas.length === 0) {
    return (
      <div style={emptyStateStyle}>
        <Tag size={48} color="#cbd5e1" />
        <p>No hay ofertas publicadas para este local.</p>
      </div>
    );
  }

  return (
    <div style={gridStyle}>
      {ofertas.map((oferta) => (
        <div key={oferta.id} style={cardStyle}>
          {/* Contenedor de Imagen */}
          <div style={imageWrapper}>
            {oferta.imagen ? (
              <img src={oferta.imagen} alt={oferta.producto} style={imgStyle} />
            ) : (
              <div style={noImageStyle}><Package size={40} color="#cbd5e1" /></div>
            )}
            <div style={badgeStyle}>Oferta</div>
          </div>

          <div style={{ padding: '20px' }}>
            <h3 style={{ margin: '0 0 5px 0', fontSize: '1.2rem' }}>{oferta.producto}</h3>
            <p style={precioStyle}>${oferta.precio}</p>
            
            <div style={infoStyle}>
              <Calendar size={14} /> 
              <span>Vence: <strong>{oferta.vencimiento}</strong></span>
            </div>
            
            {oferta.descripcion && <p style={descStyle}>{oferta.descripcion}</p>}
            
            <button onClick={() => onDelete(oferta.id)} style={btnDelete}>
              <Trash2 size={16} /> Eliminar Oferta
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

/* --- ESTILOS --- */
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '25px' };
const cardStyle = { background: 'white', borderRadius: '24px', border: '1px solid #e2e8f0', overflow: 'hidden', transition: 'transform 0.2s', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const imageWrapper = { width: '100%', height: '180px', position: 'relative', background: '#f1f5f9' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const noImageStyle = { width: '100%', height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const badgeStyle = { position: 'absolute', top: '15px', right: '15px', background: '#e67e22', color: 'white', padding: '5px 12px', borderRadius: '10px', fontSize: '0.75rem', fontWeight: 'bold' };
const precioStyle = { fontSize: '1.8rem', fontWeight: '900', color: '#1e293b', margin: '10px 0' };
const infoStyle = { display: 'flex', alignItems: 'center', gap: '6px', color: '#64748b', fontSize: '0.85rem' };
const descStyle = { fontSize: '0.85rem', color: '#475569', background: '#f8fafc', padding: '10px', borderRadius: '10px', marginTop: '15px' };
const btnDelete = { width: '100%', padding: '12px', marginTop: '15px', background: '#fff1f2', color: '#e11d48', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' };
const emptyStateStyle = { textAlign: 'center', padding: '80px 20px', background: 'white', borderRadius: '24px', border: '2px dashed #e2e8f0', color: '#64748b' };

export default ListaOfertas;
